using System;
using System.IO;
using System.Windows.Media.Imaging;

namespace MCLauncher
{
    /// <summary>
    /// Embedded icon as base64 - no external files needed
    /// </summary>
    public static class EmbeddedIcon
    {
        // PASTE YOUR BASE64 STRING HERE (replace the empty string)
        private const string BASE64_ICON = @"";

        /// <summary>
        /// Get the icon as a BitmapImage for WPF
        /// </summary>
        public static BitmapImage GetIcon()
        {
            try
            {
                if (string.IsNullOrEmpty(BASE64_ICON))
                    return null;

                byte[] imageBytes = Convert.FromBase64String(BASE64_ICON);
                
                var bitmap = new BitmapImage();
                bitmap.BeginInit();
                bitmap.CacheOption = BitmapCacheOption.OnLoad;
                bitmap.StreamSource = new MemoryStream(imageBytes);
                bitmap.EndInit();
                bitmap.Freeze(); // Make it thread-safe
                
                return bitmap;
            }
            catch
            {
                return null;
            }
        }
    }
}
